Args:
    index_path: Path to the LEANN index file
    required_fields: List of metadata field names that should be present

Returns:
    Dictionary containing:
    {
        "coverage_percentage": percentage of passages that have all required fields,
        "field_coverage": dictionary mapping field name to coverage percentage,
        "missing_fields": list of required fields not found in any passage
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    # Initialize PassageManager to access index metadata
    passage_manager = PassageManager([index_path])

    total_passages = 0
    passages_with_all_fields = 0
    field_coverages = {}
    missing_fields_in_index = []

    # Check each passage for required field presence
    for passage_id in passage_manager.passage_files:
        total_passages += 1
        has_all_required = True

        for field in required_fields:
            try:
                passage_data = passage_manager.get_passage(passage_id)
                if passage_data and "metadata" in passage_data:
                    metadata = passage_data["metadata"]
                    if field not in metadata:
                        has_all_required = False
            except KeyError:
                has_all_required = False
                continue

        if has_all_required:
            passages_with_all_fields += 1

    # Calculate coverage percentages for each field
    for field in required_fields:
        field_count = 0
        for passage_id in passage_manager.passage_files:
            try:
                passage_data = passage_manager.get_passage(passage_id)
                if passage_data and "metadata" in passage_data and field in passage_data["metadata"]:
                    field_count += 1
            except KeyError:
                continue

        field_coverages[field] = (field_count / total_passages) * 100 if total_passages > 0 else 0

    # Identify missing fields that aren't present in any passage
    all_fields_in_index = set()
    for passage_id in passage_manager.passage_files:
        try:
            passage_data = passage_manager.get_passage(passage_id)
            if passage_data and "metadata" in passage_data:
                metadata = passage_data["metadata"]
                if isinstance(metadata, dict):
                    all_fields_in_index.update(metadata.keys())
        except KeyError:
            continue

    missing_fields_in_index = [field for field in required_fields if field not in all_fields_in_index]

    # Calculate overall coverage percentage
    overall_coverage = (passages_with_all_fields / total_passages) * 100 if total_passages > 0 else 0

    return {
        "coverage_percentage": round(overall_coverage, 2),
        "field_coverage": field_coverages,
        "missing_fields": missing_fields_in_index
    }
